```plantuml
@startuml
class Capitan {
  - nombre: String
  - apellido: String
  - matricula: int
  + Capitan(nombre String, apellido String, matricula int): void
}

abstract class Embarcacion <<abstract>> {
  - capitan: Capitan
  - precioBase: double
  - valorAdicional: double
  - AñoDeFabricacion: int
  + montoDeAlquiler(): double
}

interface Comparable <<interface>> {
  + compareTo(o Object): int
}

class Yate {
  - cantCamarotes: int
  + compareTo(o Object): int
}

class Velero {
  - cantMastiles: int
  + esGrande(): boolean
}

Capitan "1" <-- "1" Embarcacion
Comparable <|.. Yate : implements
Embarcacion <|-- Yate : extends
Embarcacion <|-- Velero : extends

@enduml
```
